def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                val = np.cos(ratio * a * np.pi) * (a ** 3)
                if a % 4 == 1:
                    val *= 1.1
                elif a % 5 == 0:
                    val *= 0.85
                score += val
            if (int(capacity + item) % 4 == 1) or (int(capacity - item) % 6 == 2):
                score *= 0.75
            if score > 12:
                score /= 3
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity * 1.5) + 3):
                prod *= (ratio + np.sin(n) / (n + 1))
                if prod > 2e6:
                    prod = np.log1p(prod)**1.1
                    break
            mod_val = int(prod * 10) % 400
            score += np.sqrt(ratio * mod_val + 2)
            if (int(capacity * 1.2) % 5 == 3) and ((item * 5) % 4 == 1):
                score += 6.5
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * x**3) % 1) * (x ** 2.3) * np.tanh(x)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += increment * np.exp(-m / 7)
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.8 + np.log1p(remainder + 1)
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.35
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 15):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 2.2) * np.cos(p)
                if penalty_base > 70:
                    penalty_base = np.log1p(np.abs(penalty_base))
                    break
            score = penalty_base * 15
            if capacity < item * 1.08:
                score += 20
            if (int(capacity * 7) % 8 == 0) and (int(item * 10) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.3
                score += 7
            if score > 130:
                score = 130
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 15):
                penalty_ext += ((diff) ** q) * (q ** 3.1) / ((q + 2) ** 0.7) * np.sin(q)
            score = penalty_ext * 25
            if capacity < item * 1.4:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.2) * (np.cos(z) + 1)
            if score < 0:
                score = abs(score) * 0.6 + 1
            if score > 1500:
                score = 1500
        else:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 20):
                term = ((diff) ** r) * (r ** 3.8) * np.sin(r * 0.5)
                if abs(term) > 15000:
                    term = np.sign(term) * np.sqrt(abs(term))
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 17) % 3 == 0) and (int(item * 21) % 6 == 0):
                score -= 12
            for w in range(2, 10):
                score += ((diff / w) % 1) * (w * 2.5) * (np.sin(w) + 1)
            if score < 0:
                score = abs(score) * 0.75 + 6
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5) * 1.1
        elif capacity < 7:
            score *= 2.5 + (7 - capacity) * 0.1
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
